import{_ as t,o as a,c as n,ag as s}from"./chunks/framework.DL0AyVxm.js";const g=JSON.parse('{"title":"Skills","description":"","frontmatter":{},"headers":[],"relativePath":"reference/skills.md","filePath":"reference/skills.md"}'),i={name:"reference/skills.md"};function o(d,e,l,r,c,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h1><p>Skills are knowledge files installed to <code>.claude/skills/</code>. They teach Claude how to perform specific types of work. Unlike CLAUDE.md (which is always loaded), skills are loaded on demand -- Claude reads them only when the task at hand requires that knowledge.</p><p>CLAUDE.md contains pointers to each skill so Claude knows they exist. When working on git operations, Claude loads <code>git-conventions.md</code>. When writing tests, Claude loads <code>testing.md</code>. This keeps the active context focused.</p><h2 id="universal-skills" tabindex="-1">Universal Skills <a class="header-anchor" href="#universal-skills" aria-label="Permalink to &quot;Universal Skills&quot;">​</a></h2><p>9 skills installed with every project. These cover workflow mechanics that apply regardless of tech stack.</p><h3 id="context-management" tabindex="-1">context-management <a class="header-anchor" href="#context-management" aria-label="Permalink to &quot;context-management&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/context-management.md</code></td></tr><tr><td><strong>Description</strong></td><td>Context budget awareness, when to compact, when to clear, subagent offloading</td></tr><tr><td><strong>When loaded</strong></td><td>Mid-session when context is growing large; before deciding to compact or spawn a subagent</td></tr></tbody></table><p>Teaches the 70% rule (act before running out of context), the three tools for managing context (/compact, /clear, subagents), and a decision matrix for choosing between them. Explains how the PostCompact hook automatically re-reads CLAUDE.md and PROGRESS.md.</p><h3 id="git-conventions" tabindex="-1">git-conventions <a class="header-anchor" href="#git-conventions" aria-label="Permalink to &quot;git-conventions&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/git-conventions.md</code></td></tr><tr><td><strong>Description</strong></td><td>Branch naming, commit message format, PR workflow, worktree conventions</td></tr><tr><td><strong>When loaded</strong></td><td>Before creating branches, writing commits, or opening PRs</td></tr></tbody></table><p>Covers branch naming patterns (<code>type/short-description</code>), conventional commit format (<code>type(scope): description</code>), when to commit, the PR workflow with <code>gh</code>, squash vs merge policy, and worktree conventions for agents. Includes rules on commit message quality.</p><h3 id="planning-with-files" tabindex="-1">planning-with-files <a class="header-anchor" href="#planning-with-files" aria-label="Permalink to &quot;planning-with-files&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/planning-with-files.md</code></td></tr><tr><td><strong>Description</strong></td><td>How to structure implementation plans as files, progressive implementation, plan review process</td></tr><tr><td><strong>When loaded</strong></td><td>Before starting multi-file changes or new features</td></tr></tbody></table><p>Defines the IMPLEMENTATION-PROMPT pattern for writing plans as versioned Markdown files. Covers how to break tasks into independently testable phases, signs a phase is too big or too small, the plan-review workflow with the plan-reviewer agent, progressive implementation (one phase at a time), and when to plan vs just do it.</p><h3 id="review-and-handoff" tabindex="-1">review-and-handoff <a class="header-anchor" href="#review-and-handoff" aria-label="Permalink to &quot;review-and-handoff&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/review-and-handoff.md</code></td></tr><tr><td><strong>Description</strong></td><td>Session ending protocol, HANDOFF document format, seamless continuation between sessions</td></tr><tr><td><strong>When loaded</strong></td><td>At session end or when ending mid-task. Triggered by the <code>/end</code> command.</td></tr></tbody></table><p>Defines the session ending protocol (commit, test, update PROGRESS.md, write handoff if mid-task). Specifies the PROGRESS.md update format and the HANDOFF document structure for mid-task endings. Includes the &quot;fresh session test&quot; for handoff quality: could a fresh session continue without asking questions?</p><h3 id="prompt-engineering" tabindex="-1">prompt-engineering <a class="header-anchor" href="#prompt-engineering" aria-label="Permalink to &quot;prompt-engineering&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/prompt-engineering.md</code></td></tr><tr><td><strong>Description</strong></td><td>Effective prompting patterns for working with Claude, demanding quality, writing specs</td></tr><tr><td><strong>When loaded</strong></td><td>When crafting instructions for subagents or writing spec documents</td></tr></tbody></table><p>Covers how to demand quality and elegance from Claude, when to be specific vs delegate, writing detailed specs, using the IMPLEMENTATION-PROMPT as a prompt, and model-level guidance (Opus for judgment, Sonnet for implementation, Haiku for validation). Lists prompting anti-patterns to avoid.</p><h3 id="verification" tabindex="-1">verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;verification&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/verification.md</code></td></tr><tr><td><strong>Description</strong></td><td>Domain-specific verification beyond tests, closing the feedback loop</td></tr><tr><td><strong>When loaded</strong></td><td>After implementing changes, before committing. Triggered by the <code>/verify</code> command.</td></tr></tbody></table><p>Covers verification strategies for web applications (dev server, manual testing), APIs (beyond happy path), CLIs (edge case arguments, exit codes), and data pipelines (schema checks, record counts). Defines the feedback loop pattern (change, verify, commit) and the full build verification suite.</p><h3 id="testing" tabindex="-1">testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;testing&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/testing.md</code></td></tr><tr><td><strong>Description</strong></td><td>Test philosophy, coverage strategy, test-first patterns, what to test and what not to</td></tr><tr><td><strong>When loaded</strong></td><td>When writing or reviewing tests. Used by the <code>test-writer</code> agent.</td></tr></tbody></table><p>Teaches test philosophy (behavior not implementation), meaningful coverage vs line coverage, edge cases worth testing, the test-first workflow, Arrange-Act-Assert structure, test naming as specifications, and testing anti-patterns (snapshot abuse, mock everything, testing the framework).</p><h3 id="claude-md-maintenance" tabindex="-1">claude-md-maintenance <a class="header-anchor" href="#claude-md-maintenance" aria-label="Permalink to &quot;claude-md-maintenance&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/claude-md-maintenance.md</code></td></tr><tr><td><strong>Description</strong></td><td>How Claude writes rules for itself, when to update CLAUDE.md, keeping it lean</td></tr><tr><td><strong>When loaded</strong></td><td>When updating CLAUDE.md. Triggered by the <code>/update-claude-md</code> command.</td></tr></tbody></table><p>Explains the self-healing pattern (same mistake twice becomes a rule), the 50-line target for CLAUDE.md, what belongs in CLAUDE.md vs skills, Gotchas section format and maintenance, and when to prune. Distinguishes between CLAUDE.md (always loaded, instructions) and skills (loaded on demand, knowledge).</p><h3 id="subagent-usage" tabindex="-1">subagent-usage <a class="header-anchor" href="#subagent-usage" aria-label="Permalink to &quot;subagent-usage&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/subagent-usage.md</code></td></tr><tr><td><strong>Description</strong></td><td>When to use subagents, how many, context hygiene, worktree isolation patterns</td></tr><tr><td><strong>When loaded</strong></td><td>Before spawning subagents for testing, code review, or parallel work</td></tr></tbody></table><p>Covers when subagents help vs when they do not, context hygiene (offloading to keep the main session clean), parallel vs sequential subagents (limit to 2-3 parallel), worktree isolation mechanics, and how to give subagents good instructions. Emphasizes that subagents start with zero context and need explicit instructions.</p><hr><h2 id="template-skills" tabindex="-1">Template Skills <a class="header-anchor" href="#template-skills" aria-label="Permalink to &quot;Template Skills&quot;">​</a></h2><p>3 skills scaffolded with placeholder content during <code>worclaude init</code>. These contain HTML comments as prompts explaining what to fill in for each section. The <code>/setup</code> command interviews the user and populates them automatically.</p><h3 id="backend-conventions" tabindex="-1">backend-conventions <a class="header-anchor" href="#backend-conventions" aria-label="Permalink to &quot;backend-conventions&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/backend-conventions.md</code></td></tr><tr><td><strong>Description</strong></td><td>Stack-specific backend patterns, API design, database access, error handling conventions</td></tr></tbody></table><p>Placeholder sections: API Patterns, Database Access, Error Handling, Authentication, Logging, Configuration Management. Each section includes HTML comment prompts asking specific questions (e.g., &quot;Which ORM/query builder/driver is used?&quot;, &quot;What HTTP status codes map to which error types?&quot;).</p><h3 id="frontend-design-system" tabindex="-1">frontend-design-system <a class="header-anchor" href="#frontend-design-system" aria-label="Permalink to &quot;frontend-design-system&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/frontend-design-system.md</code></td></tr><tr><td><strong>Description</strong></td><td>Design system, component library, styling approach, accessibility and responsive design standards</td></tr></tbody></table><p>Placeholder sections: Component Library, Styling Approach, State Management, Accessibility Standards, Responsive Design. Prompts cover topics like component naming, CSS methodology, state management solution, WCAG level, and breakpoint strategy.</p><h3 id="project-patterns" tabindex="-1">project-patterns <a class="header-anchor" href="#project-patterns" aria-label="Permalink to &quot;project-patterns&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>File</strong></td><td><code>.claude/skills/project-patterns.md</code></td></tr><tr><td><strong>Description</strong></td><td>Architectural patterns, naming conventions, file organization, error handling philosophy</td></tr></tbody></table><p>Placeholder sections: Architecture Overview, Naming Conventions, File Organization, Common Patterns, Error Handling Philosophy. Prompts cover high-level architecture, directory structure philosophy, design patterns in use, and error classification approach.</p><h3 id="template-skill-lifecycle" tabindex="-1">Template Skill Lifecycle <a class="header-anchor" href="#template-skill-lifecycle" aria-label="Permalink to &quot;Template Skill Lifecycle&quot;">​</a></h3><ol><li><code>worclaude init</code> creates the files with placeholder sections containing HTML comment prompts.</li><li>User runs <code>/setup</code> in a Claude Code session.</li><li>Claude conducts a 7-section interview about the project.</li><li>Claude fills each template skill with real, project-specific content based on interview answers.</li><li>Skills are now loaded on demand for all future sessions.</li></ol><p>Template skills can also be filled manually by editing the Markdown files directly and replacing the HTML comment placeholders with actual conventions. Sections that do not apply to the project can be deleted.</p><hr><h2 id="adding-custom-skills" tabindex="-1">Adding Custom Skills <a class="header-anchor" href="#adding-custom-skills" aria-label="Permalink to &quot;Adding Custom Skills&quot;">​</a></h2><p>Custom skills can be added by creating new <code>.md</code> files in <code>.claude/skills/</code>. They follow the same format as universal skills. Custom skills are not tracked by <code>worclaude diff</code> or <code>worclaude upgrade</code> -- they are fully user-managed.</p><p>To make Claude aware of a custom skill, add a pointer to CLAUDE.md&#39;s Skills section:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Skills (read on demand, not upfront)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">See </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`.claude/skills/\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — load only what&#39;s relevant:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...existing skills...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my-custom-skill.md — Description of when to use it</span></span></code></pre></div><hr><h2 id="skill-file-format" tabindex="-1">Skill File Format <a class="header-anchor" href="#skill-file-format" aria-label="Permalink to &quot;Skill File Format&quot;">​</a></h2><p>Every skill file uses YAML frontmatter with a <code>description</code> field, followed by Markdown content:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">description: &#39;Brief description of what this skill teaches&#39;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Skill Name</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content organized by topic with headers, lists, code examples,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tables, and a Gotchas section at the end.</span></span></code></pre></div><p>The <code>description</code> field appears in Claude&#39;s skill listing, helping it decide which skill to load.</p><hr><h2 id="skill-file-location" tabindex="-1">Skill File Location <a class="header-anchor" href="#skill-file-location" aria-label="Permalink to &quot;Skill File Location&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/skills/</span></span>
<span class="line"><span>  context-management.md       # universal</span></span>
<span class="line"><span>  git-conventions.md          # universal</span></span>
<span class="line"><span>  planning-with-files.md      # universal</span></span>
<span class="line"><span>  review-and-handoff.md       # universal</span></span>
<span class="line"><span>  prompt-engineering.md       # universal</span></span>
<span class="line"><span>  verification.md             # universal</span></span>
<span class="line"><span>  testing.md                  # universal</span></span>
<span class="line"><span>  claude-md-maintenance.md    # universal</span></span>
<span class="line"><span>  subagent-usage.md           # universal</span></span>
<span class="line"><span>  backend-conventions.md      # template</span></span>
<span class="line"><span>  frontend-design-system.md   # template</span></span>
<span class="line"><span>  project-patterns.md         # template</span></span></code></pre></div><p>Skills can be customized after installation. Additional custom skills can be added to the same directory. The <code>worclaude diff</code> command tracks modifications to installed skills.</p><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/Worclaude/reference/claude-md.html">CLAUDE.md Template</a> -- how skills are referenced from CLAUDE.md</li><li><a href="/Worclaude/reference/slash-commands.html">Slash Commands</a> -- <code>/setup</code> fills template skills automatically</li><li><a href="/Worclaude/reference/agents.html">Agents</a> -- agents that rely on skills (e.g., test-writer uses testing.md)</li></ul>`,64)])])}const m=t(i,[["render",o]]);export{g as __pageData,m as default};
